    await refresh()
  }, [refresh])

  const removeCategory = useCallback(async (id: number) => {
    await ipc.deleteCategory(id)
    await refresh()
  }, [refresh])

  return { categories, loading, refresh, addCategory, editCategory, removeCategory }
}

