const fs = require('fs');
// Create a valid 16x16 32-bit ICO file with a purple (#6366f1) color
const W = 16, H = 16;
// BMP pixel data (BGRA format, bottom-to-top)
const pixelData = Buffer.alloc(W * H * 4);
for (let i = 0; i < W * H; i++) {
  // Purple: R=99 G=102 B=241 A=255
  // BGRA: B=241 G=102 R=99 A=255
  pixelData[i*4+0] = 241; // B
  pixelData[i*4+1] = 102; // G
  pixelData[i*4+2] = 99;  // R
  pixelData[i*4+3] = 255; // A
}
// AND mask (1-bit, rows padded to 4 bytes) — all zeros = fully opaque
const maskRows = Math.ceil(W / 8);
const maskPad = (4 - maskRows % 4) % 4;
const maskRowSize = maskRows + maskPad;
const maskData = Buffer.alloc(H * maskRowSize, 0);

// BITMAPINFOHEADER (40 bytes)
const bmpHeader = Buffer.alloc(40);
bmpHeader.writeUInt32LE(40, 0);          // biSize
bmpHeader.writeInt32LE(W, 4);            // biWidth
bmpHeader.writeInt32LE(H * 2, 8);        // biHeight (doubled for ICO)
bmpHeader.writeUInt16LE(1, 12);          // biPlanes
bmpHeader.writeUInt16LE(32, 14);         // biBitCount
bmpHeader.writeUInt32LE(0, 16);          // biCompression (BI_RGB)
bmpHeader.writeUInt32LE(pixelData.length + maskData.length, 20); // biSizeImage
bmpHeader.writeInt32LE(0, 24);           // biXPelsPerMeter
bmpHeader.writeInt32LE(0, 28);           // biYPelsPerMeter
bmpHeader.writeUInt32LE(0, 32);          // biClrUsed
bmpHeader.writeUInt32LE(0, 36);          // biClrImportant

const imageData = Buffer.concat([bmpHeader, pixelData, maskData]);
const imageSize = imageData.length;
const imageOffset = 6 + 16; // ICONDIR + ICONDIRENTRY

// ICONDIR (6 bytes)
const iconDir = Buffer.alloc(6);
iconDir.writeUInt16LE(0, 0);   // reserved
iconDir.writeUInt16LE(1, 2);   // type = 1 (ICO)
iconDir.writeUInt16LE(1, 4);   // count = 1

// ICONDIRENTRY (16 bytes)
const iconEntry = Buffer.alloc(16);
iconEntry.writeUInt8(W, 0);            // width
iconEntry.writeUInt8(H, 1);            // height
iconEntry.writeUInt8(0, 2);            // colorCount
iconEntry.writeUInt8(0, 3);            // reserved
iconEntry.writeUInt16LE(1, 4);         // planes
iconEntry.writeUInt16LE(32, 6);        // bitCount
iconEntry.writeUInt32LE(imageSize, 8); // sizeInBytes
iconEntry.writeUInt32LE(imageOffset, 12); // imageOffset

const ico = Buffer.concat([iconDir, iconEntry, imageData]);
fs.writeFileSync('resources/icon.ico', ico);
