/* Task completion: flash primary color, scale up, then shrink + fade */
@keyframes task-complete {
  0%   { transform: scale(1);    opacity: 1;   background-color: transparent; }
  20%  { transform: scale(1.02); opacity: 1;   background-color: hsl(var(--primary) / 0.15); }
  60%  { transform: scale(0.97); opacity: 0.6; background-color: hsl(var(--primary) / 0.08); }
  100% { transform: scale(0.95); opacity: 0;   background-color: transparent; }
}

.animate-task-complete {
  animation: task-complete 0.55s ease-in-out forwards;
}

