const fs = require('fs');
const zlib = require('zlib');

const W = 256, H = 256;
const R = 99, G = 102, B = 241; // #6366f1 purple

// CRC32 table
const crcTable = [];
for (let i = 0; i < 256; i++) {
  let c = i;
  for (let j = 0; j < 8; j++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
  crcTable[i] = c;
}
function crc32(buf) {
  let crc = 0xFFFFFFFF;
  for (let i = 0; i < buf.length; i++) crc = crcTable[(crc ^ buf[i]) & 0xFF] ^ (crc >>> 8);
  return (crc ^ 0xFFFFFFFF) >>> 0;
}

function chunk(type, data) {
  const t = Buffer.from(type, 'ascii');
  const len = Buffer.alloc(4); len.writeUInt32BE(data.length, 0);
  const crcVal = Buffer.alloc(4); crcVal.writeUInt32BE(crc32(Buffer.concat([t, data])), 0);
  return Buffer.concat([len, t, data, crcVal]);
}

// IHDR: 256x256, 8-bit RGB
const ihdr = Buffer.alloc(13);
ihdr.writeUInt32BE(W, 0); ihdr.writeUInt32BE(H, 4);
ihdr[8]=8; ihdr[9]=2; ihdr[10]=0; ihdr[11]=0; ihdr[12]=0;

// Raw scanlines with filter byte 0 (None)
const raw = Buffer.alloc(H * (1 + W * 3));
for (let y = 0; y < H; y++) {
  raw[y * (1 + W*3)] = 0;
  for (let x = 0; x < W; x++) {
    const o = y*(1+W*3)+1+x*3;
    // Add a dark rounded rect look: corners and center dot
    const cx = x - 128, cy = y - 128;
    const r2 = cx*cx + cy*cy;
    const inRoundRect = x>=20&&x<236&&y>=20&&y<236;
    let pr = R, pg = G, pb = B;
    if (!inRoundRect) { pr=15; pg=15; pb=17; } // bg color outside rect
    else if (r2 < 1200) { pr=255; pg=255; pb=255; } // white center dot
    raw[o]=pr; raw[o+1]=pg; raw[o+2]=pb;
  }
}

const compressed = zlib.deflateSync(raw, { level: 1 });
const sig = Buffer.from([137,80,78,71,13,10,26,10]);
const png = Buffer.concat([sig, chunk('IHDR',ihdr), chunk('IDAT',compressed), chunk('IEND',Buffer.alloc(0))]);

// ICO wrapping the PNG (width/height=0 means 256 in ICO spec)
const iconDir = Buffer.alloc(6);
iconDir.writeUInt16LE(0,0); iconDir.writeUInt16LE(1,2); iconDir.writeUInt16LE(1,4);
const entry = Buffer.alloc(16);
entry[0]=0; entry[1]=0; entry[2]=0; entry[3]=0;
entry.writeUInt16LE(1,4); entry.writeUInt16LE(32,6);
entry.writeUInt32LE(png.length,8); entry.writeUInt32LE(22,12);

fs.writeFileSync('resources/icon.ico', Buffer.concat([iconDir, entry, png]));
console.log('Icon written OK, PNG bytes:', png.length);
